class Solution {
    public int countKDifference(int[] nums, int k) {
        int count = 0;
        int[] freq = new int[101];

        for (int num : nums) {
            freq[num]++;
        }

        for (int num : nums) {
            if (num - k >= 0) {
                count += freq[num - k];
            }
            if (num + k <= 100) {
                count += freq[num + k];
            }
        }

        return count / 2;
    }
}
